// 1. No arguments → parentheses required
Runnable hello = () -> System.out.println("hi");

// 2. One argument → parentheses optional
Function<String, Integer> len = s -> s.length();

// 3. Multiple arguments → parentheses required
Comparator<String> byLen = (a, b) -> a.length() - b.length();

// 4. Statement block → curly braces + explicit return
Function<Integer, String> classify = n -> {
  if (n < 0) return "negative";
  if (n == 0) return "zero";
  return "positive";
};

// Types are usually inferred; you rarely need to write them out.
// If you do: (String a, String b) -> a.length() - b.length();

// All equivalent. Prefer the last form when it reads clearly.
list.forEach(x -> System.out.println(x));
list.forEach(System.out::println);

names.stream().map(s -> s.toUpperCase()).toList();
names.stream().map(String::toUpperCase).toList();

int base = 10;                              // effectively final (never reassigned)
Function<Integer, Integer> addBase = x -> x + base;   // OK

int counter = 0;
Runnable r = () -> counter++;               // COMPILE ERROR — must be effectively final

// Workaround for accumulation: use AtomicInteger or a mutable holder
AtomicInteger safeCounter = new AtomicInteger();
Runnable r2 = () -> safeCounter.incrementAndGet();     // OK — the reference is final;
                                                        // the object it points to is mutable

// File: LambdaDemo.java
// Run: javac LambdaDemo.java && java LambdaDemo
import java.util.*;
import java.util.function.*;
import java.util.stream.*;

public class LambdaDemo {
  public static void main(String[] args) {
    // 1. Runnable — no arg, no return
    Runnable greet = () -> System.out.println("hello");
    greet.run();

    // 2. Function<T, R>
    Function<String, Integer> length = String::length;    // method reference
    System.out.println("length of 'hello' = " + length.apply("hello"));

    // 3. Predicate<T>
    Predicate<Integer> isEven = n -> n % 2 == 0;
    Predicate<Integer> isPositive = n -> n > 0;
    System.out.println("6 even? " + isEven.test(6));
    System.out.println("6 even AND positive? " + isEven.and(isPositive).test(6));   // composition
    System.out.println("NOT even? " + isEven.negate().test(6));

    // 4. Consumer<T>
    Consumer<String> printer = System.out::println;
    List.of("a", "b", "c").forEach(printer);

    // 5. Supplier<T>
    Supplier<List<Integer>> newList = ArrayList::new;
    List<Integer> fresh = newList.get();
    fresh.add(42);
    System.out.println(fresh);

    // 6. BiFunction<T, U, R>
    BiFunction<Integer, Integer, Integer> add = (a, b) -> a + b;
    System.out.println("sum = " + add.apply(3, 4));

    // 7. Sorting with a lambda comparator
    List<String> names = new ArrayList<>(List.of("Ada", "Zoe", "Kim"));
    names.sort((a, b) -> a.length() - b.length());
    System.out.println("by length: " + names);
    names.sort(Comparator.reverseOrder());
    System.out.println("reverse alpha: " + names);

    // 8. Function composition
    Function<Integer, Integer> addOne = x -> x + 1;
    Function<Integer, Integer> triple = x -> x * 3;
    System.out.println("triple then addOne: " + triple.andThen(addOne).apply(5));   // 16
    System.out.println("addOne then triple: " + addOne.andThen(triple).apply(5));   // 18

    // 9. Variable capture (effectively final)
    String prefix = "user:";
    Function<Integer, String> label = id -> prefix + id;
    System.out.println(label.apply(42));

    // 10. Streams — the main destination of lambdas
    int sumOfEvenSquares = IntStream.rangeClosed(1, 10)
        .filter(n -> n % 2 == 0)
        .map(n -> n * n)
        .sum();
    System.out.println("even squares 1..10: " + sumOfEvenSquares);
  }
}

// Expected output:
//   hello
//   length of 'hello' = 5
//   6 even? true
//   6 even AND positive? true
//   NOT even? false
//   a
//   b
//   c
//   [42]
//   sum = 7
//   by length: [Ada, Zoe, Kim]
//   reverse alpha: [Zoe, Kim, Ada]
//   triple then addOne: 16
//   addOne then triple: 18
//   user:42
//   even squares 1..10: 220
